// dotenv-shape parse: takes a string, returns parsed key→value record.
// BSD-2-Clause. Idiomatic older-JS structure typical of dotenv-shape
// libraries. Subpath export so consumers can `import { parse } from
// "dotenv/parse"`.

const LINE = /^\s*(?:export\s+)?([\w.\-]+)\s*=\s*(.*?)\s*$/;

export function parse(src) {
    const out = {};
    const lines = src.toString().split(/\r?\n/);
    for (const line of lines) {
        if (!line || line.startsWith("#")) continue;
        const m = LINE.exec(line);
        if (!m) continue;
        let value = m[2] || "";
        // Strip surrounding quotes; preserve content between matching pair.
        const first = value[0];
        const last = value[value.length - 1];
        if (value.length >= 2 && (first === '"' || first === "'") && first === last) {
            value = value.slice(1, -1);
            // For double quotes, interpret common escapes.
            if (first === '"') {
                value = value
                    .replace(/\\n/g, "\n")
                    .replace(/\\r/g, "\r")
                    .replace(/\\t/g, "\t")
                    .replace(/\\"/g, '"')
                    .replace(/\\\\/g, "\\");
            }
        }
        out[m[1]] = value;
    }
    return out;
}
